module RefModule (
    input clk,
    input [31:0] unsorted, // 4 unsigned 8-bit integers
    output reg [31:0] sorted // 4 unsigned 8-bit integers
);
    reg [7:0] obf_array [0:3];
    integer i, j;

    always @(posedge clk) begin
        // Load inputs into obf_array
        for (i = 0; i < 4; i = i + 1) begin
            obf_array[i] = unsorted[8*i +: 8];
        end

        // Merge sort implementation
        // Simple implementation for 4 elements
        for (i = 0; i < 4; i = i + 1) begin
            for (j = i + 1; j < 4; j = j + 1) begin
                if (obf_array[i] > obf_array[j]) begin
                    // Swap
                    {obf_array[i], obf_array[j]} = {obf_array[j], obf_array[i]};
                end
            end
        end

        // Load sorted results to output
        sorted = {obf_array[3], obf_array[2], obf_array[1], obf_array[0]};
    end
endmodule
